params.css:
:root {
  --color-primary: #6366f1;
  --color-primary-dark: #4f46e5;
  --color-accent: #a5b4fc;
  --color-bg: #0f0f13;
  --color-bg-2: #16161d;
  --color-bg-card: #1c1c26;
  --color-border: #2a2a3a;
  --color-text: #e2e2f0;
  --color-text-muted: #8888aa;
  --color-code-bg: #12121a;
  --radius: 10px;
  --font: 'Segoe UI', system-ui, sans-serif;
  --font-mono: 'Fira Mono', 'Courier New', monospace;
}

* { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: var(--font);
  background: var(--color-bg);
  color: var(--color-text);
  line-height: 1.65;
  min-height: 100vh;
}

a { color: var(--color-accent); text-decoration: none; }
a:hover { color: var(--color-primary); }

/* NAV */
.main-nav {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0.9rem 2.5rem;
  background: rgba(15,15,19,0.92);
  backdrop-filter: blur(10px);
  border-bottom: 1px solid var(--color-border);
  position: sticky;
  top: 0;
  z-index: 100;
}
.nav-logo { display: flex; align-items: center; }
.logo-img {
    height: 75px;
    width: auto;
}
.nav-links { display: flex; gap: 2rem; align-items: center; }
.nav-link {
  font-size: 0.95rem;
  font-weight: 500;
  color: var(--color-text-muted);
  transition: color 0.2s;
  padding: 0.25rem 0;
  border-bottom: 2px solid transparent;
}
.nav-link:hover, .nav-link.active {
  color: var(--color-text);
  border-bottom-color: var(--color-primary);
}

/* BUTTONS */
.btn {
  display: inline-block;
  padding: 0.65rem 1.4rem;
  border-radius: var(--radius);
  font-weight: 600;
  font-size: 0.95rem;
  transition: all 0.2s;
  cursor: pointer;
}
.btn-primary {
  background: var(--color-primary);
  color: #fff;
}
.btn-primary:hover {
  background: var(--color-primary-dark);
  color: #fff;
  transform: translateY(-1px);
  box-shadow: 0 4px 20px rgba(99,102,241,0.35);
}
.btn-outline {
  background: transparent;
  color: var(--color-text);
  border: 1px solid var(--color-border);
}
.btn-outline:hover {
  border-color: var(--color-primary);
  color: var(--color-accent);
}
.btn-large { padding: 0.85rem 2rem; font-size: 1rem; }

/* HOME */
.home-page {}

.hero {
  text-align: center;
  padding: 6rem 2rem 5rem;
  background: radial-gradient(ellipse 80% 60% at 50% 0%, rgba(99,102,241,0.18) 0%, transparent 70%);
}
.hero-logo {
    height: 250px;
    width: auto;
    margin-bottom: 1.8rem;
    filter: drop-shadow(0 0 18px rgba(99,102,241,0.5));
}
.hero h1 {
  font-size: clamp(2rem, 5vw, 3.2rem);
  font-weight: 800;
  letter-spacing: -0.02em;
  margin-bottom: 1.2rem;
  background: linear-gradient(135deg, #fff 30%, var(--color-accent));
  -webkit-background-clip: text;
  -webkit-text-fill-color: transparent;
  background-clip: text;
}
.hero-subtitle {
  font-size: 1.15rem;
  color: var(--color-text-muted);
  max-width: 600px;
  margin: 0 auto 2.2rem;
}
.hero-cta { display: flex; gap: 1rem; justify-content: center; flex-wrap: wrap; }

.stats-section {
  padding: 3rem 2rem;
  background: var(--color-bg-2);
  border-top: 1px solid var(--color-border);
  border-bottom: 1px solid var(--color-border);
}
.stats-grid {
  display: flex;
  justify-content: center;
  gap: 4rem;
  flex-wrap: wrap;
  max-width: 800px;
  margin: 0 auto;
}
.stat-card { text-align: center; }
.stat-number {
  display: block;
  font-size: 2.5rem;
  font-weight: 800;
  color: var(--color-primary);
  line-height: 1;
  margin-bottom: 0.4rem;
}
.stat-label {
  font-size: 0.9rem;
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
}

.features-section {
  padding: 5rem 2rem;
  max-width: 1100px;
  margin: 0 auto;
  text-align: center;
}
.features-section h2 {
  font-size: 2rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
}
.section-subtitle {
  color: var(--color-text-muted);
  margin-bottom: 3rem;
  font-size: 1.05rem;
}
.features-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
  gap: 1.5rem;
}
.feature-card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 2rem 1.5rem;
  text-align: left;
  transition: border-color 0.2s, transform 0.2s;
}
.feature-card:hover {
  border-color: var(--color-primary);
  transform: translateY(-3px);
}
.feature-icon {
  font-size: 1.8rem;
  margin-bottom: 1rem;
}
.feature-card h3 {
  font-size: 1.05rem;
  font-weight: 700;
  margin-bottom: 0.5rem;
}
.feature-card p { color: var(--color-text-muted); font-size: 0.92rem; }

.cta-section {
  background: linear-gradient(135deg, rgba(99,102,241,0.12), rgba(99,102,241,0.04));
  border-top: 1px solid var(--color-border);
  border-bottom: 1px solid var(--color-border);
  text-align: center;
  padding: 5rem 2rem;
}
.cta-section h2 { font-size: 1.9rem; font-weight: 700; margin-bottom: 1rem; }
.cta-section p { color: var(--color-text-muted); margin-bottom: 2rem; max-width: 500px; margin-left: auto; margin-right: auto; }

/* DOCS LAYOUT */
.docs-page {
  display: flex;
  min-height: calc(100vh - 64px);
}
.docs-sidebar {
  width: 260px;
  flex-shrink: 0;
  background: var(--color-bg-2);
  border-right: 1px solid var(--color-border);
  padding: 2rem 1.5rem;
  position: sticky;
  top: 64px;
  height: calc(100vh - 64px);
  overflow-y: auto;
}
.docs-sidebar-logo {
  width: 60px;
  height: auto;
  margin-bottom: 1rem;
}
.docs-sidebar h3 {
  font-size: 0.8rem;
  text-transform: uppercase;
  letter-spacing: 0.08em;
  color: var(--color-text-muted);
  margin-bottom: 1rem;
}
.docs-nav { display: flex; flex-direction: column; gap: 0.3rem; }
.docs-nav-link {
  display: block;
  padding: 0.55rem 0.75rem;
  border-radius: 6px;
  font-size: 0.9rem;
  color: var(--color-text-muted);
  transition: all 0.15s;
}
.docs-nav-link:hover, .docs-nav-link.active {
  background: rgba(99,102,241,0.15);
  color: var(--color-text);
}
.docs-nav-link.active { color: var(--color-accent); font-weight: 600; }

.docs-content {
  flex: 1;
  padding: 3rem 3.5rem;
  max-width: 860px;
}
.docs-header { margin-bottom: 3rem; }
.docs-header h1 { font-size: 2rem; font-weight: 800; margin-bottom: 0.75rem; }
.docs-lead { font-size: 1.1rem; color: var(--color-text-muted); }

.docs-section { margin-bottom: 3rem; }
.docs-section h2 {
  font-size: 1.35rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--color-border);
}
.docs-section p { color: var(--color-text-muted); margin-bottom: 1rem; }
.requirements-list { color: var(--color-text-muted); padding-left: 1.4rem; }
.requirements-list li { margin-bottom: 0.4rem; }

.step-block {
  display: flex;
  gap: 1.2rem;
  margin-bottom: 1.8rem;
  align-items: flex-start;
}
.step-number {
  flex-shrink: 0;
  width: 32px;
  height: 32px;
  border-radius: 50%;
  background: var(--color-primary);
  color: #fff;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.85rem;
  font-weight: 700;
  margin-top: 2px;
}
.step-block h4 { font-size: 1rem; font-weight: 600; margin-bottom: 0.4rem; }
.step-block p { color: var(--color-text-muted); font-size: 0.92rem; }

.code-block {
  background: var(--color-code-bg);
  border: 1px solid var(--color-border);
  border-radius: 7px;
  padding: 1rem 1.2rem;
  margin-top: 0.75rem;
  overflow-x: auto;
  font-family: var(--font-mono);
  font-size: 0.85rem;
  color: #a5b4fc;
  white-space: pre;
}

.docs-next {
  background: rgba(99,102,241,0.08);
  border: 1px solid rgba(99,102,241,0.25);
  border-radius: var(--radius);
  padding: 1.5rem 2rem;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  flex-wrap: wrap;
}
.docs-next p { color: var(--color-text-muted); }

/* COMMANDS PAGE */
.commands-intro {
  display: flex;
  align-items: center;
  gap: 1.5rem;
  margin-bottom: 2.5rem;
  flex-wrap: wrap;
}
.commands-intro p { color: var(--color-text-muted); flex: 1; min-width: 200px; }
.badge-count {
  flex-shrink: 0;
  background: linear-gradient(135deg, var(--color-primary), #a78bfa);
  color: #fff;
  padding: 0.4rem 1rem;
  border-radius: 999px;
  font-weight: 700;
  font-size: 0.9rem;
}

.cmd-section { margin-bottom: 3rem; }
.cmd-section h2 {
  font-size: 1.35rem;
  font-weight: 700;
  margin-bottom: 0.75rem;
  padding-bottom: 0.5rem;
  border-bottom: 1px solid var(--color-border);
}
.cmd-section > p { color: var(--color-text-muted); margin-bottom: 1.2rem; }

.cmd-card {
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  border-radius: var(--radius);
  padding: 1.5rem;
  margin-bottom: 1rem;
}
.cmd-header {
  display: flex;
  align-items: center;
  gap: 1rem;
  margin-bottom: 0.75rem;
}
.cmd-name {
  font-size: 1rem;
  font-weight: 700;
  font-family: var(--font-mono);
  color: var(--color-accent);
}
.cmd-method {
  font-size: 0.72rem;
  font-weight: 700;
  padding: 0.2rem 0.55rem;
  border-radius: 4px;
  letter-spacing: 0.06em;
  text-transform: uppercase;
}
.method-post { background: rgba(34,197,94,0.15); color: #4ade80; border: 1px solid rgba(34,197,94,0.3); }
.method-patch { background: rgba(251,191,36,0.12); color: #fbbf24; border: 1px solid rgba(251,191,36,0.3); }
.method-put { background: rgba(59,130,246,0.12); color: #60a5fa; border: 1px solid rgba(59,130,246,0.3); }
.cmd-card > p { color: var(--color-text-muted); font-size: 0.92rem; margin-bottom: 1rem; }
.cmd-card h5 { font-size: 0.8rem; text-transform: uppercase; letter-spacing: 0.07em; color: var(--color-text-muted); margin-bottom: 0.4rem; }

/* 404 PAGE */
.page-404 {
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: calc(100vh - 130px);
  padding: 3rem 2rem;
}
.error-container {
  text-align: center;
  max-width: 480px;
}
.error-img {
  width: 220px;
  height: auto;
  margin-bottom: 2rem;
  opacity: 0.9;
}
.error-code {
  font-size: 2rem;
  font-weight: 800;
  margin-bottom: 0.75rem;
}
.error-message {
  color: var(--color-text-muted);
  margin-bottom: 2rem;
  font-size: 1.05rem;
}

/* FOOTER */
.site-footer {
  background: var(--color-bg-2);
  border-top: 1px solid var(--color-border);
  padding: 2.5rem 2.5rem 1.5rem;
}
.footer-inner {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  flex-wrap: wrap;
  gap: 2rem;
  max-width: 1100px;
  margin: 0 auto 2rem;
}
.footer-brand {}
.footer-logo { height: 32px; width: auto; margin-bottom: 0.5rem; }
.footer-brand p { color: var(--color-text-muted); font-size: 0.88rem; }
.footer-links { display: flex; gap: 1.5rem; align-items: center; flex-wrap: wrap; }
.footer-links a { color: var(--color-text-muted); font-size: 0.88rem; transition: color 0.2s; }
.footer-links a:hover { color: var(--color-text); }
.github-icon { height: 22px; width: auto; opacity: 0.7; transition: opacity 0.2s; }
.github-icon:hover { opacity: 1; }
.footer-copy {
  text-align: center;
  color: var(--color-text-muted);
  font-size: 0.82rem;
  border-top: 1px solid var(--color-border);
  padding-top: 1.2rem;
  max-width: 1100px;
  margin: 0 auto;
}

/* LANG SWITCH */
.lang-switch { display: flex; gap: 0.5rem; margin-top: 1rem; justify-content: center; }
.lang-btn {
  padding: 0.3rem 0.75rem;
  border-radius: 5px;
  font-size: 0.82rem;
  background: var(--color-bg-card);
  border: 1px solid var(--color-border);
  color: var(--color-text-muted);
  transition: all 0.2s;
}
.lang-btn:hover { border-color: var(--color-primary); color: var(--color-text); }

@media (max-width: 768px) {
  .docs-page { flex-direction: column; }
  .docs-sidebar { width: 100%; height: auto; position: static; }
  .docs-content { padding: 2rem 1.5rem; }
  .stats-grid { gap: 2rem; }
  .docs-next { flex-direction: column; }
  .main-nav { padding: 0.9rem 1.2rem; }
}

.nav-menu-images {
    height: 25px;
    margin-top: 10px;
}
